example.code:
const typeDefs = gql`
  extend schema
    @link(url: "https://specs.apollo.dev/federation/v2.3",
          import: ["@key", "@shareable", "@external", "@requires"])

  type User @key(fields: "id") {
    id: ID!
    email: String!
    name: String!
    createdAt: DateTime!
  }

  type Query {
    user(id: ID!): User
    me: User
  }
`;

const resolvers = {
  User: {
    __resolveReference: async (user, { dataSources }) => {
      return dataSources.usersAPI.getUser(user.id);
    },
  },
};

const typeDefs = gql`
  extend schema
    @link(url: "https://specs.apollo.dev/federation/v2.3",
          import: ["@key", "@shareable", "@external", "@requires"])

  type Product @key(fields: "id") {
    id: ID!
    name: String!
    price: Float!
    seller: User!
  }

  # Extend User from users subgraph — add products field
  extend type User @key(fields: "id") {
    id: ID! @external
    products: [Product!]!
  }
`;

const resolvers = {
  User: {
    products: async (user, _, { dataSources }) => {
      return dataSources.productsAPI.getProductsBySeller(user.id);
    },
  },
};

// DO NOT MIX v1 and v2 — this will fail rover compose
const typeDefs = gql`
  type User @key(fields: "id") {  // v1: no extend schema @link
    id: ID! @external             // @external on key field is wrong in v2
    email: String! @requires(fields: "id")  // misuse of @requires
  }
`;
